    private async fetchWithRetry(url: string, retries: number = 1): Promise<Response | null> {
        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                const response = await fetch(url, {
                    headers: this.headers,
                    redirect: 'follow',
                })
                if (response.ok) return response
                if (attempt === retries) return null
            } catch {
                if (attempt === retries) return null
            }
        }
        return null
    }

    private async searchCatalog(query: string): Promise<SearchResult[]> {
        const urls = [
            `${this.baseUrl}/manga/`,
            `${this.baseUrl}/manga/page/2/`,
            `${this.baseUrl}/manga/page/3/`,
        ]

        const results = new Map<string, SearchResult>()
        const normalizedQuery = this.normalizeText(query)

        for (const url of urls) {
            const response = await this.fetchWithRetry(url)
            if (!response) continue

            const html = await response.text()
            const $ = LoadDoc(html)

            $('a[href*="/manga/"]').each((_: number, element: any) => {
                const href = String(element.attr('href') || '').trim()
                const title = this.cleanTitle(String(element.attr('title') || element.text() || '').trim())
                if (!href || !title || /\/capitulo-/i.test(href)) return

                const mangaId = this.extractMangaId(href)
                if (!mangaId) return

                const score = this.scoreTitleMatch(normalizedQuery, title)
                if (score <= 0) return

                const id = `mangalivre:${mangaId}`
                if (results.has(id)) return

                results.set(id, {
                    id,
                    title,
                    image: undefined,
                })
            })
        }

        return Array.from(results.values())
    }

    private async tryDirectSlug(slug: string, fallbackTitle: string): Promise<SearchResult | null> {
        if (!slug) return null

        const url = `${this.baseUrl}/manga/${slug}/`
        const response = await this.fetchWithRetry(url)
        if (!response) return null

        const finalUrl = String((response as any).url || url)
        const mangaId = this.extractMangaId(finalUrl)
        if (!mangaId) return null

        const html = await response.text()
        const $ = LoadDoc(html)
        const title = this.cleanTitle(String($('h1').first().text() || $('title').first().text() || fallbackTitle).trim())

        return {
            id: mangaId,
            title,
            image: undefined,
        }
    }

    private extractMangaId(url: string): string | null {
        const match = String(url || '').match(/\/manga\/([^\/]+)\/?/i)
        return match ? match[1] : null
    }

    private extractChapterToken(url: string, title: string): string | null {
        const urlMatch = String(url || '').match(/capitulo-([^\/]+)\/?/i)
        if (urlMatch) return urlMatch[1].replace(/_/g, '.').replace(/,/g, '.')

        const titleMatch = String(title || '').match(/cap(?:[íi]tulo)?\s*([0-9]+(?:[\.,_][0-9]+)?)/i)
        if (titleMatch) return titleMatch[1].replace(/_/g, '.').replace(/,/g, '.')

        return null
    }

    private extractImageUrl(element: any): string | undefined {
        if (!element) return undefined
        const img = element.find ? element.find(this.selectors.search.image).first() : element
        const src = String(img?.attr?.('data-src') || img?.attr?.('data-lazy-src') || img?.attr?.('data-srcset') || img?.attr?.('src') || '').trim()
        return this.normalizeUrl(this.pickImageCandidate(src) || '') || undefined
    }

    private extractImageFromAttrs(element: any): string | undefined {
        if (!element) return undefined
        const attrs = [
            element.attr?.('data-src'),
            element.attr?.('data-lazy-src'),
            element.attr?.('data-srcset'),
            element.attr?.('src'),
            element.attr?.('style'),
        ]
        for (const value of attrs) {
            const found = this.pickImageCandidate(String(value || ''))
            if (found) return this.normalizeUrl(found) || undefined
        }
        return undefined
    }

    private pickImageCandidate(value: string): string | undefined {
        const raw = String(value || '').trim()
        if (!raw) return undefined
        const first = raw.split(',')[0]?.trim().split(/\s+/)[0]?.trim()
        const url = first || raw
        const styleMatch = raw.match(/url\((["']?)(.*?)\)/i)
        const candidate = styleMatch?.[2] || url
        if (!candidate || /^data:/i.test(candidate)) return undefined
        return candidate
    }

    private normalizeUrl(url: string): string | null {
        const value = String(url || '').trim()
        if (!value) return null
        if (value.startsWith('//')) return `https:${value}`
        if (value.startsWith('/')) return `${this.baseUrl}${value}`
        return value
    }

    private normalizeText(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, ' ')
            .replace(/\s+/g, ' ')
            .trim()
    }

    private scoreTitleMatch(query: string, title: string): number {
        const q = this.normalizeText(query)
        const t = this.normalizeText(title)
        if (!q || !t) return 0
        if (q === t) return 100
        if (t.includes(q)) return 80

        const stopwords = new Set(['a', 'o', 'as', 'os', 'de', 'da', 'do', 'das', 'dos', 'e', 'em', 'no', 'na', 'nos', 'nas', 'the', 'of', 'and'])
        const words = q.split(' ').filter(word => word.length >= 3 && !stopwords.has(word))
        if (words.length === 0) return 0

        let hits = 0
        for (const word of words) {
            if (t.includes(word)) hits += 1
        }

        if (hits === words.length) return 60 + hits * 10
        if (hits > 0) return hits * 20
        return 0
    }

    private isLikelyMangaTitle(title: string, query: string): boolean {
        const cleaned = this.cleanTitle(title)
        const normalized = this.normalizeText(cleaned)
        if (!cleaned || cleaned.length < 2 || !normalized) return false
        if (/novos mangas|mangas mais lidos|recem adicionados|adicionados recentemente/.test(normalized)) return false
        if (/^[0-9\s]+$/.test(cleaned)) return false
        return this.scoreTitleMatch(query, cleaned) >= 20
    }

    private cleanTitle(value: string): string {
        return String(value || '')
            .replace(/\s+/g, ' ')
            .replace(/\s*-\s*Manga Livre.*$/i, '')
            .trim()
    }

    private slugify(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/^-+|-+$/g, '')
    }

    private chapterSortValue(value: string): number {
        const parts = String(value || '').split('.')
        const main = parseFloat(parts[0].replace(',', '.'))
        if (!Number.isFinite(main)) return Number.MAX_SAFE_INTEGER
        if (parts.length === 1) return main
        const decimal = parseFloat(`0.${parts.slice(1).join('')}`)
        return main + (Number.isFinite(decimal) ? decimal : 0)
    }

    private normalizeMangaId(mangaId: string): string {
        const value = String(mangaId || '').trim()
        const prefixed = value.match(/^[a-z0-9_-]+:(.+)$/i)
        return prefixed ? String(prefixed[1] || '').trim() : value
    }

    private isValidMangaId(mangaId: string): boolean {
        return typeof mangaId === 'string' && /^[a-z0-9-]+$/i.test(mangaId)
    }

    private isValidChapterId(chapterId: string): boolean {
        return typeof chapterId === 'string' && chapterId.startsWith('http')
    }
}

class MangaFireProvider {
    private api = "https://mangafire.to";

    getSettings(): Settings {
        return {
            supportsMultiLanguage: false,
            supportsMultiScanlator: false,
        };
    }

    async search(opts: { query: string }): Promise<SearchResult[]> {
        const query = String(opts?.query || '').trim()
        if (!query) return []
        const vrf = this.generate(query)
        const res = await fetch(`${this.api}/ajax/manga/search?keyword=${query.replaceAll(" ", "+")}&vrf=${vrf}`)
        const data = await res.json()

        if (!data?.result?.html) return []

        const $ = LoadDoc(data.result.html)
        const normalizedQuery = this.normalizeText(query)
        const queryTokens = normalizedQuery.split(' ').filter(token => token.length >= 3)
        const seen = new Map<string, SearchResult>()

        $("a.unit").each((i, e) => {
            const id = String(e.attr("href") || '').replace('/manga/', '').trim()
            const rawTitle = String(e.find("h6").text() || '').trim()
            const image = e.find("img").attr("src")
            const title = this.cleanTitle(rawTitle)
            const normalizedTitle = this.normalizeText(title)
            if (!id || !title || !normalizedTitle) return
            if (normalizedTitle.includes(normalizedQuery) === false) {
                const hits = queryTokens.filter(token => normalizedTitle.includes(token)).length
                if (queryTokens.length > 1 && hits !== queryTokens.length) return
                if (queryTokens.length <= 1 && hits === 0) return
            }
            const dedupeKey = normalizedTitle.replace(/\s* 1 \s*$/, '').trim()
            if (seen.has(dedupeKey)) return
            seen.set(dedupeKey, {
                id: `mangafire:${id}`,
                title,
                synonyms: [],
                year: 1,
                image
            })
        })

        return Array.from(seen.values())
    }

    async findChapters(mangaId: string): Promise<ChapterDetails[]> {
        const preferredLanguages = ['pt-br', 'pt']
        for (const lang of preferredLanguages) {
            const chapters = await this.fetchChaptersForLanguage(mangaId, lang)
            if (chapters.length > 0) {
                return chapters.map((chapter, index) => ({ ...chapter, index, language: lang === 'pt-br' ? 'pt-BR' : 'pt' }))
            }
        }
        return []
    }

    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        // Para chapter pages, el input es "chapter@" + chapterId
        const vrf = this.generate("chapter@" + chapterId);
        const res = await fetch(`${this.api}/ajax/read/chapter/${chapterId}?vrf=${vrf}`);
        const data = await res.json();
        const images = data.result?.images;

        if (!images?.length) return [];

        return images.map((img: any[], i: number) => ({
            url: img[0],
            index: i,
            headers: {
                Referer: `${this.api}`,
            },
        }));
    }

    // ------------------------
    // AUXILIAR FUNCTIONS
    // ------------------------

    private extractLanguageCodes(html: string): string[] {
        const $ = LoadDoc(html);
        const langMap = new Map<string, string>();

        $("[data-code][data-title]").each((i, e) => {
            let code = e.attr("data-code")?.toLowerCase() || "";
            const title = e.attr("data-title") || "";

            if (code === 'es' && title.includes('LATAM')) code = 'es-la';
            else if (code === 'pt' && title.includes('Br')) code = 'pt-br';

            langMap.set(code, code);
        });

        return Array.from(langMap.values());
    }

    private async fetchChaptersForLanguage(mangaId: string, lang: string): Promise<ChapterDetails[]> {
        const mangaIdShort = mangaId.split(".").pop() || "";

        const vrf = this.generate(mangaIdShort + "@chapter@" + lang);

        const res = await fetch(
            `${this.api}/ajax/read/${mangaIdShort}/chapter/${lang}?vrf=${vrf}`
        );

        const data = await res.json();
        const html = data.result?.html || "";

        if (!html) return [];

        const $ = LoadDoc(html);
        const langChapters: ChapterDetails[] = [];

        $("a[data-number][data-id]").each((i, e) => {
            const url = e.attr("href") || "";
            const chapter = e.attr("data-number") || "";
            const id = e.attr("data-id") || "";
            const title = e.attr("title") || "";
            const language = this.normalizeLanguageCode(lang);

            langChapters.push({
                id: `mangafire:${id}`,
                url: `${this.api}${url}`,
                title,   // lo dejamos vacío si no existe
                chapter,
                index: 0,
                language,
            });
        });

        langChapters.reverse();

        langChapters.forEach((ch, i) => {
            ch.index = i;
            if (!ch.title) {
                ch.title = `chapter ${i + 1}`;
            }
        });

        return langChapters;
    }

    private normalizeLanguageCode(lang: string): string {
        const langToISO: Record<string, string> = {
            'en': 'en',
            'fr': 'fr',
            'es': 'es',
            'es-la': 'es-419',
            'pt': 'pt',
            'pt-br': 'pt-br',
            'ja': 'ja',
            'de': 'de',
            'it': 'it',
            'ru': 'ru',
            'ko': 'ko',
            'zh': 'zh',
            'zh-cn': 'zh-cn',
            'zh-tw': 'zh-tw',
            'ar': 'ar',
            'tr': 'tr',
        };

        return langToISO[lang] || lang;
    }

    private textEncode(str: string): Uint8Array {
        return Uint8Array.from(Buffer.from(str, "utf-8"));
    }

    private textDecode(bytes: Uint8Array): string {
        return Buffer.from(bytes).toString("utf-8");
    }

    private atob(data: string): Uint8Array {
        return Uint8Array.from(Buffer.from(data, 'base64'));
    }

    private btoa(data: Uint8Array): string {
        return Buffer.from(data).toString('base64');
    }

    private add8(n: number): (c: number) => number {
        return (c: number) => (c + n) & 0xff;
    }

    private sub8(n: number): (c: number) => number {
        return (c: number) => (c - n + 256) & 0xff;
    }

    private xor8(n: number): (c: number) => number {
        return (c: number) => (c ^ n) & 0xff;
    }

    private rotl8(n: number): (c: number) => number {
        return (c: number) => ((c << n) | (c >> (8 - n))) & 0xff;
    }

    private rotr8(n: number): (c: number) => number {
        return (c: number) => ((c >> n) | (c << (8 - n))) & 0xff;
    }

    private scheduleC = [
        this.sub8(223), this.rotr8(4), this.rotr8(4), this.add8(234), this.rotr8(7),
        this.rotr8(2), this.rotr8(7), this.sub8(223), this.rotr8(7), this.rotr8(6),
    ];

    private scheduleY = [
        this.add8(19), this.rotr8(7), this.add8(19), this.rotr8(6), this.add8(19),
        this.rotr8(1), this.add8(19), this.rotr8(6), this.rotr8(7), this.rotr8(4),
    ];

    private scheduleB = [
        this.sub8(223), this.rotr8(1), this.add8(19), this.sub8(223), this.rotl8(2),
        this.sub8(223), this.add8(19), this.rotl8(1), this.rotl8(2), this.rotl8(1),
    ];

    private scheduleJ = [
        this.add8(19), this.rotl8(1), this.rotl8(1), this.rotr8(1), this.add8(234),
        this.rotl8(1), this.sub8(223), this.rotl8(6), this.rotl8(4), this.rotl8(1),
    ];

    private scheduleE = [
        this.rotr8(1), this.rotl8(1), this.rotl8(6), this.rotr8(1), this.rotl8(2),
        this.rotr8(4), this.rotl8(1), this.rotl8(1), this.sub8(223), this.rotl8(2),
    ];

    private rc4Keys: Record<string, string> = {
        l: "FgxyJUQDPUGSzwbAq/ToWn4/e8jYzvabE+dLMb1XU1o=",
        g: "CQx3CLwswJAnM1VxOqX+y+f3eUns03ulxv8Z+0gUyik=",
        B: "fAS+otFLkKsKAJzu3yU+rGOlbbFVq+u+LaS6+s1eCJs=",
        m: "Oy45fQVK9kq9019+VysXVlz1F9S1YwYKgXyzGlZrijo=",
        F: "aoDIdXezm2l3HrcnQdkPJTDT8+W6mcl2/02ewBHfPzg=",
    };

    private seeds32: Record<string, string> = {
        A: "yH6MXnMEcDVWO/9a6P9W92BAh1eRLVFxFlWTHUqQ474=",
        V: "RK7y4dZ0azs9Uqz+bbFB46Bx2K9EHg74ndxknY9uknA=",
        N: "rqr9HeTQOg8TlFiIGZpJaxcvAaKHwMwrkqojJCpcvoc=",
        P: "/4GPpmZXYpn5RpkP7FC/dt8SXz7W30nUZTe8wb+3xmU=",
        k: "wsSGSBXKWA9q1oDJpjtJddVxH+evCfL5SO9HZnUDFU8=",
    };

    private prefixKeys: Record<string, string> = {
        O: "l9PavRg=",
        v: "Ml2v7ag1Jg==",
        L: "i/Va0UxrbMo=",
        p: "WFjKAHGEkQM=",
        W: "5Rr27rWd",
    };

    private rc4(key: Uint8Array, input: Uint8Array): Uint8Array {
        const s = new Uint8Array(256);
        for (let i = 0; i < 256; i++) s[i] = i;

        let j = 0;
        for (let i = 0; i < 256; i++) {
            j = (j + s[i] + key[i % key.length]) & 0xff;
            [s[i], s[j]] = [s[j], s[i]];
        }

        const output = new Uint8Array(input.length);
        let i = 0;
        j = 0;
        for (let y = 0; y < input.length; y++) {
            i = (i + 1) & 0xff;
            j = (j + s[i]) & 0xff;
            [s[i], s[j]] = [s[j], s[i]];
            const k = s[(s[i] + s[j]) & 0xff];
            output[y] = input[y] ^ k;
        }

        return output;
    }

    private transform(
        input: Uint8Array,
        initSeedBytes: Uint8Array,
        prefixKeyBytes: Uint8Array,
        prefixLen: number,
        schedule: ((c: number) => number)[]
    ): Uint8Array {
        const out: number[] = [];
        for (let i = 0; i < input.length; i++) {
            if (i < prefixLen) {
                out.push(prefixKeyBytes[i] || 0);
            }
            const transformed = schedule[i % 10]((input[i] ^ initSeedBytes[i % 32]) & 0xff) & 0xff;
            out.push(transformed);
        }
        return new Uint8Array(out);
    }

    generate(input: string): string {
        let encodedInput = encodeURIComponent(input);
        let bytes = this.textEncode(encodedInput);

        // Etapa 1: RC4 con clave "l" + Transform con schedule_c
        bytes = this.rc4(this.atob(this.rc4Keys["l"]), bytes);
        const prefix_O = this.atob(this.prefixKeys["O"]);
        bytes = this.transform(bytes, this.atob(this.seeds32["A"]), prefix_O, prefix_O.length, this.scheduleC);

        // Etapa 2: RC4 con clave "g" + Transform con schedule_y
        bytes = this.rc4(this.atob(this.rc4Keys["g"]), bytes);
        const prefix_v = this.atob(this.prefixKeys["v"]);
        bytes = this.transform(bytes, this.atob(this.seeds32["V"]), prefix_v, prefix_v.length, this.scheduleY);

        // Etapa 3: RC4 con clave "B" + Transform con schedule_b
        bytes = this.rc4(this.atob(this.rc4Keys["B"]), bytes);
        const prefix_L = this.atob(this.prefixKeys["L"]);
        bytes = this.transform(bytes, this.atob(this.seeds32["N"]), prefix_L, prefix_L.length, this.scheduleB);

        // Etapa 4: RC4 con clave "m" + Transform con schedule_j
        bytes = this.rc4(this.atob(this.rc4Keys["m"]), bytes);
        const prefix_p = this.atob(this.prefixKeys["p"]);
        bytes = this.transform(bytes, this.atob(this.seeds32["P"]), prefix_p, prefix_p.length, this.scheduleJ);

        // Etapa 5: RC4 con clave "F" + Transform con schedule_e
        bytes = this.rc4(this.atob(this.rc4Keys["F"]), bytes);
        const prefix_W = this.atob(this.prefixKeys["W"]);
        bytes = this.transform(bytes, this.atob(this.seeds32["k"]), prefix_W, prefix_W.length, this.scheduleE);

        // Base64URL encode
        return this.btoa(bytes).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
    }
}
